sys_script_client.script:
function onChange(control, oldValue, newValue, isLoading, isTemplate) {
    if (isLoading || newValue === '') {
        return;
    }

	//created by : Sandesh Bhale , Created on : 22-07-2026 , Purpose : field visibility according to software asset type

    if (newValue == 'software') {
        g_form.setDisplay('model', false);
		g_form.setMandatory('business_justification', true);
    } else {
		g_form.setDisplay('model', true);
        g_form.setMandatory('business_justification', false);
    }
}
